using ModelContextProtocol.Server;
using System.ComponentModel;

namespace ConfigMcpServer.Tools;

[McpServerToolType]
public static class GreetingTools
{
    [McpServerTool, Description("Returns a personalized greeting message.")]
    public static string Greet(
        [Description("Name of the person to greet")] string name)
    {
        return $"Hello, {name}! Welcome to the ConfigMcpServer.";
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

namespace ConfigMcpServer.Resources;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(UriTemplate = "config://app/settings", Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Environment = "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { DarkMode = true, BetaAccess = false }
        };
        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://app/version", Name = "App Version",
        MimeType = "text/plain"),
     Description("Returns the current application version string.")]
    public static string GetVersion() => "1.0.0";
}

